static const uint8_t _pins[]={25,26};static bool _state[2]={false};
void relay_setup(){for(int i=0;i<2;i++){pinMode(_pins[i],OUTPUT);digitalWrite(_pins[i],HIGH);}Serial.println("[relay] OK");}
void relay_set(uint8_t ch,bool on){if(ch>=2)return;_state[ch]=on;digitalWrite(_pins[ch],on?LOW:HIGH);Serial.printf("[relay] CH%d=%s\n",ch,on?"ON":"OFF");}
bool relay_get(uint8_t ch){return ch<2?_state[ch]:false;}
void relay_toggle(uint8_t ch){if(ch<2)relay_set(ch,!_state[ch]);}

