#include "stepper_a4988.h"
#include <Arduino.h>
#define STEP_PIN 25
#define DIR_PIN 26
#define EN_PIN 27
static int _stepsLeft=0;static bool _cw=true;
static unsigned long _stepDelay=1000;static unsigned long _lastStep=0;
void stepper_setup(){pinMode(STEP_PIN,OUTPUT);pinMode(DIR_PIN,OUTPUT);pinMode(EN_PIN,OUTPUT);digitalWrite(EN_PIN,LOW);Serial.println("[stepper] OK");}
void stepper_loop(){
  if(_stepsLeft<=0)return;
  if(micros()-_lastStep<_stepDelay)return;
  _lastStep=micros();
  digitalWrite(STEP_PIN,HIGH);delayMicroseconds(2);digitalWrite(STEP_PIN,LOW);
  _stepsLeft--;
}
void stepper_move(int s,bool cw){_stepsLeft=abs(s);_cw=cw;digitalWrite(DIR_PIN,cw?HIGH:LOW);}
void stepper_set_speed(int rpm){_stepDelay=60000000UL/(200*rpm);}
void stepper_enable(bool en){digitalWrite(EN_PIN,en?LOW:HIGH);}

