#include "led_output.h"

int LedOutput::pin = 2; // Default pin configuration
bool LedOutput::inverted = false; // Default inversion configuration

void LedOutput::setup() {
    pinMode(pin, OUTPUT);
    digitalWrite(pin, inverted ? HIGH : LOW); // Initialize to default state
}

void LedOutput::loop(bool trigger) {
    if (trigger != digitalRead(pin)) {
        digitalWrite(pin, inverted ? !trigger : trigger);
        Serial.println("[led_output] LED toggled");
    }
}

bool LedOutput::getPinState() {
    return digitalRead(pin);
}

