void ServoMotor::setup(int pin, int min_pulse, int max_pulse) {
    servo.attach(pin, min_pulse, max_pulse);
    if (!servo.attached()) {
        Serial.println("[servo_motor] Failed to attach servo motor. Retrying...");
        delay(1000);
        setup(pin, min_pulse, max_pulse); // Retry
    }
}

