#include "i2s_microphone.h"
#include "config.h"

#define I2S_MIC_PORT I2S_NUM_0
#define I2S_BUFFER_SIZE 1024

static int32_t _micBuffer[I2S_BUFFER_SIZE];
static size_t _samplesRead = 0;
static float _rmsLevel = 0.0f;
static float _peakLevel = 0.0f;

void i2s_mic_setup() {
    i2s_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX),
        .sample_rate = 16000,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_32BIT,
        .channel_format = I2S_CHANNEL_FMT_ONLY_LEFT,
        .communication_format = I2S_COMM_FORMAT_STAND_I2S,
        .intr_alloc_flags = ESP_INTR_FLAG_LEVEL1,
        .dma_buf_count = 4,
        .dma_buf_len = I2S_BUFFER_SIZE,
        .use_apll = false,
        .tx_desc_auto_clear = false,
        .fixed_mclk = 0
    };
    i2s_pin_config_t pin_config = {
        .bck_io_num = 26,
        .ws_io_num = 25,
        .data_out_num = I2S_PIN_NO_CHANGE,
        .data_in_num = 22
    };
    i2s_driver_install(I2S_MIC_PORT, &i2s_config, 0, NULL);
    i2s_set_pin(I2S_MIC_PORT, &pin_config);
    Serial.println("[i2s-mic] INMP441 ready @ 16kHz");
}

void i2s_mic_loop() {
    size_t bytesRead = 0;
    i2s_read(I2S_MIC_PORT, _micBuffer, sizeof(_micBuffer), &bytesRead, portMAX_DELAY);
    _samplesRead = bytesRead / sizeof(int32_t);

    // Calculate RMS and peak
    float sumSq = 0;
    _peakLevel = 0;
    for (size_t i = 0; i < _samplesRead; i++) {
        float sample = (float)(_micBuffer[i] >> 14) / 32768.0f;
        sumSq += sample * sample;
        float absSample = fabs(sample);
        if (absSample > _peakLevel) _peakLevel = absSample;
    }
    _rmsLevel = sqrt(sumSq / _samplesRead);
}

float i2s_mic_get_rms() { return _rmsLevel; }
float i2s_mic_get_peak() { return _peakLevel; }
int32_t* i2s_mic_get_buffer() { return _micBuffer; }
size_t i2s_mic_get_samples_read() { return _samplesRead; }

