#include "i2s_speaker.h"
#include "config.h"

#define I2S_SPK_PORT I2S_NUM_1
static bool _spkPlaying = false;

void i2s_speaker_setup() {
    i2s_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX),
        .sample_rate = 16000,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_ONLY_LEFT,
        .communication_format = I2S_COMM_FORMAT_STAND_I2S,
        .intr_alloc_flags = ESP_INTR_FLAG_LEVEL1,
        .dma_buf_count = 8,
        .dma_buf_len = 1024,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0
    };
    i2s_pin_config_t pin_config = {
        .bck_io_num = 27,
        .ws_io_num = 14,
        .data_out_num = 12,
        .data_in_num = I2S_PIN_NO_CHANGE
    };
    i2s_driver_install(I2S_SPK_PORT, &i2s_config, 0, NULL);
    i2s_set_pin(I2S_SPK_PORT, &pin_config);
    Serial.println("[i2s-spk] MAX98357A ready");
}

void i2s_speaker_play(const int16_t* data, size_t samples) {
    size_t bytesWritten;
    _spkPlaying = true;
    i2s_write(I2S_SPK_PORT, data, samples * sizeof(int16_t), &bytesWritten, portMAX_DELAY);
}

void i2s_speaker_tone(float freqHz, int durationMs) {
    const int sampleRate = 16000;
    int totalSamples = sampleRate * durationMs / 1000;
    int16_t buf[256];
    _spkPlaying = true;
    for (int i = 0; i < totalSamples; i += 256) {
        int chunk = min(256, totalSamples - i);
        for (int j = 0; j < chunk; j++) {
            buf[j] = (int16_t)(sin(2.0 * M_PI * freqHz * (i + j) / sampleRate) * 16000);
        }
        size_t bw;
        i2s_write(I2S_SPK_PORT, buf, chunk * sizeof(int16_t), &bw, portMAX_DELAY);
    }
    _spkPlaying = false;
}

void i2s_speaker_stop() {
    i2s_zero_dma_buffer(I2S_SPK_PORT);
    _spkPlaying = false;
}

bool i2s_speaker_is_playing() { return _spkPlaying; }

