#include "ble_server.h"
#include <BLEDevice.h>
#include <BLEServer.h>
#include <BLEUtils.h>
#include <BLE2902.h>
#include "config.h"

BLEServer* _bleServer = nullptr;
BLECharacteristic* _bleChar = nullptr;
bool _bleConnected = false;
String ble_received_data = "";

class BLECallbacks : public BLEServerCallbacks {
    void onConnect(BLEServer* s) { _bleConnected = true; Serial.println("[ble] Connected"); }
    void onDisconnect(BLEServer* s) { _bleConnected = false; Serial.println("[ble] Disconnected"); s->startAdvertising(); }
};

class CharCallbacks : public BLECharacteristicCallbacks {
    void onWrite(BLECharacteristic* c) {
        ble_received_data = String(c->getValue().c_str());
        Serial.printf("[ble] Received: %s\n", ble_received_data.c_str());
    }
};

void ble_server_setup() {
    BLEDevice::init("Parakram-BLE");
    _bleServer = BLEDevice::createServer();
    _bleServer->setCallbacks(new BLECallbacks());
    BLEService* svc = _bleServer->createService("4fafc201-1fb5-459e-8fcc-c5c9c331914b");
    _bleChar = svc->createCharacteristic("beb5483e-36e1-4688-b7f5-ea07361b26a8",
        BLECharacteristic::PROPERTY_READ | BLECharacteristic::PROPERTY_WRITE | BLECharacteristic::PROPERTY_NOTIFY);
    _bleChar->addDescriptor(new BLE2902());
    _bleChar->setCallbacks(new CharCallbacks());
    svc->start();
    _bleServer->getAdvertising()->start();
    Serial.println("[ble] Server started");
}

void ble_server_loop() {}

void ble_server_notify(const char* data) {
    if (_bleConnected && _bleChar) {
        _bleChar->setValue(data);
        _bleChar->notify();
    }
}

bool ble_server_connected() { return _bleConnected; }

