    : _alpha(constrain(alpha, 0.0f, 1.0f)), _output(0.0f), _initialized(false) {}

float LowPassFilter::update(float newValue) {
    if (!_initialized) {
        _output = newValue;
        _initialized = true;
    } else {
        _output = _alpha * newValue + (1.0f - _alpha) * _output;
    }
    return _output;
}

