#include <Arduino.h>

class PIDController {
public:
    PIDController(float kp, float ki, float kd, float setpoint = 0.0f);
    float compute(float measurement);
    void setTunings(float kp, float ki, float kd);
    void setSetpoint(float sp);
    void setOutputLimits(float min, float max);
    void reset();
    float getError() const;
private:
    float _kp, _ki, _kd;
    float _setpoint;
    float _integral, _prevError;
    float _outMin, _outMax;
    unsigned long _lastTime;
};

#endif
===SOURCE===
#include "pid_controller.h"

PIDController::PIDController(float kp, float ki, float kd, float setpoint)
    : _kp(kp), _ki(ki), _kd(kd), _setpoint(setpoint),
      _integral(0), _prevError(0), _outMin(0), _outMax(100),
      _lastTime(0) {}

float PIDController::compute(float measurement) {
    unsigned long now = millis();
    float dt = (_lastTime == 0) ? 0.1f : (now - _lastTime) / 1000.0f;
    _lastTime = now;
    if (dt <= 0) dt = 0.001f;

    float error = _setpoint - measurement;
    _integral += error * dt;
    float derivative = (error - _prevError) / dt;
    _prevError = error;

    float output = _kp * error + _ki * _integral + _kd * derivative;
    return constrain(output, _outMin, _outMax);
}

void PIDController::setTunings(float kp, float ki, float kd) {
    _kp = kp; _ki = ki; _kd = kd;
}

void PIDController::setSetpoint(float sp) { _setpoint = sp; }

void PIDController::setOutputLimits(float min, float max) {
    _outMin = min; _outMax = max;
}

void PIDController::reset() {
    _integral = 0; _prevError = 0; _lastTime = 0;
}

float PIDController::getError() const { return _prevError; }

