#include "weighted_average.h"

WeightedAverage::WeightedAverage(int inputCount, float* weights)
    : _count(inputCount), _result(0.0f) {
    _inputs = new float[inputCount];
    _weights = new float[inputCount];
    for (int i = 0; i < inputCount; i++) {
        _inputs[i] = 0.0f;
        _weights[i] = weights ? weights[i] : 1.0f / inputCount;
    }
}

void WeightedAverage::setInput(int index, float value) {
    if (index >= 0 && index < _count) _inputs[index] = value;
}

float WeightedAverage::compute() {
    _result = 0.0f;
    float totalWeight = 0.0f;
    for (int i = 0; i < _count; i++) {
        _result += _inputs[i] * _weights[i];
        totalWeight += _weights[i];
    }
    if (totalWeight > 0) _result /= totalWeight;
    return _result;
}

float WeightedAverage::getResult() const { return _result; }

