#include "i2c_oled.h"
#include <Wire.h>

#define SCREEN_W 128
#define SCREEN_H 64

static Adafruit_SSD1306 _oled(SCREEN_W, SCREEN_H, &Wire, -1);

void oled_setup() {
    Wire.begin(21, 22);
    if (!_oled.begin(SSD1306_SWITCHCAPVCC, 0x3C)) {
        Serial.println("[oled] SSD1306 failed!");
        return;
    }
    _oled.clearDisplay();
    _oled.setTextSize(1);
    _oled.setTextColor(SSD1306_WHITE);
    _oled.setCursor(0, 0);
    _oled.println("Parakram AI");
    _oled.display();
    Serial.println("[oled] SSD1306 ready");
}

void oled_clear() {
    _oled.clearDisplay();
}

void oled_text(const char* text, int x, int y, int size) {
    _oled.setTextSize(size);
    _oled.setCursor(x, y);
    _oled.print(text);
}

void oled_value(const char* label, float value, int x, int y) {
    _oled.setCursor(x, y);
    _oled.printf("%s: %.1f", label, value);
}

void oled_progress(int x, int y, int w, int h, float percent) {
    _oled.drawRect(x, y, w, h, SSD1306_WHITE);
    int fillW = (int)(w * percent / 100.0f);
    _oled.fillRect(x, y, fillW, h, SSD1306_WHITE);
}

void oled_display() {
    _oled.display();
}

