// RAII-style lock guard
class SemLock {
public:
    SemLock(SemaphoreHandle_t sem, uint32_t timeoutMs = 1000);
    ~SemLock();
    bool acquired() const;
private:
    SemaphoreHandle_t _sem;
    bool _acquired;
};

