===SOURCE===
#include "rtos_timer.h"

static TimerCallback _userCallbacks[8] = {nullptr};
static int _cbIndex = 0;

static void _timerDispatch(TimerHandle_t xTimer) {
    int idx = (int)(uintptr_t)pvTimerGetTimerID(xTimer);
    if (idx >= 0 && idx < 8 && _userCallbacks[idx]) {
        _userCallbacks[idx]();
    }
}

TimerHandle_t rtos_timer_create(const char* name, uint32_t periodMs, bool autoReload, TimerCallback cb) {
    int idx = _cbIndex++;
    if (idx >= 8) {
        Serial.println("[rtos-timer] Max 8 timers");
        return nullptr;
    }
    _userCallbacks[idx] = cb;

    TimerHandle_t timer = xTimerCreate(
        name, pdMS_TO_TICKS(periodMs), 
        autoReload ? pdTRUE : pdFALSE,
        (void*)(uintptr_t)idx,
        _timerDispatch
    );

    if (timer) {
        Serial.printf("[rtos-timer] '%s' created (%lums, %s)\n", name, periodMs, autoReload ? "periodic" : "one-shot");
    }
    return timer;
}

bool rtos_timer_start(TimerHandle_t timer) {
    return timer ? (xTimerStart(timer, 0) == pdPASS) : false;
}

bool rtos_timer_stop(TimerHandle_t timer) {
    return timer ? (xTimerStop(timer, 0) == pdPASS) : false;
}

bool rtos_timer_change_period(TimerHandle_t timer, uint32_t newPeriodMs) {
    return timer ? (xTimerChangePeriod(timer, pdMS_TO_TICKS(newPeriodMs), 0) == pdPASS) : false;
}

bool rtos_timer_reset(TimerHandle_t timer) {
    return timer ? (xTimerReset(timer, 0) == pdPASS) : false;
}

