#include "api_key_vault.h"
#include <Preferences.h>

Preferences _vault;

void vault_setup() {
    _vault.begin("secrets", false);
    Serial.println("[vault] Secure key storage ready");
}

bool vault_store(const char* key, const char* value) {
    size_t written = _vault.putString(key, value);
    if (written > 0) {
        Serial.printf("[vault] Stored key '%s' (%d bytes)\n", key, written);
        return true;
    }
    return false;
}

String vault_retrieve(const char* key) {
    String val = _vault.getString(key, "");
    if (val.length() == 0) Serial.printf("[vault] Key '%s' not found\n", key);
    return val;
}

bool vault_delete(const char* key) {
    return _vault.remove(key);
}

