#include "encrypted_storage.h"
#include <Preferences.h>
#include "mbedtls/aes.h"

Preferences _encStore;
static const uint8_t _aesKey[32] = {0}; // Set your 256-bit key

void encrypted_storage_setup() {
    _encStore.begin("encrypted", false);
    Serial.println("[enc-store] Encrypted storage ready");
}

bool encrypted_store(const char* key, const uint8_t* data, size_t len) {
    // Pad to 16-byte blocks
    size_t padLen = ((len / 16) + 1) * 16;
    uint8_t* padded = (uint8_t*)calloc(padLen, 1);
    memcpy(padded, data, len);
    uint8_t* encrypted = (uint8_t*)malloc(padLen);

    mbedtls_aes_context aes;
    mbedtls_aes_init(&aes);
    mbedtls_aes_setkey_enc(&aes, _aesKey, 256);

    for (size_t i = 0; i < padLen; i += 16) {
        mbedtls_aes_crypt_ecb(&aes, MBEDTLS_AES_ENCRYPT, padded + i, encrypted + i);
    }
    mbedtls_aes_free(&aes);

    size_t written = _encStore.putBytes(key, encrypted, padLen);
    free(padded); free(encrypted);
    return written > 0;
}

size_t encrypted_load(const char* key, uint8_t* buffer, size_t maxLen) {
    size_t encLen = _encStore.getBytesLength(key);
    if (encLen == 0 || encLen > maxLen) return 0;

    uint8_t* encrypted = (uint8_t*)malloc(encLen);
    _encStore.getBytes(key, encrypted, encLen);

    mbedtls_aes_context aes;
    mbedtls_aes_init(&aes);
    mbedtls_aes_setkey_dec(&aes, _aesKey, 256);

    for (size_t i = 0; i < encLen; i += 16) {
        mbedtls_aes_crypt_ecb(&aes, MBEDTLS_AES_DECRYPT, encrypted + i, buffer + i);
    }
    mbedtls_aes_free(&aes);
    free(encrypted);
    return encLen;
}

