#include "bmp280_pressure.h"

void BMP280Pressure::setup(uint8_t i2c_address, int sda_pin, int scl_pin) {
    _i2c_address = i2c_address;
    _sda_pin = sda_pin;
    _scl_pin = scl_pin;

    Wire.begin(_sda_pin, _scl_pin);

    uint8_t retries = 5;
    while (retries--) {
        if (bmp.begin(_i2c_address)) {
            Serial.println("[bmp280_pressure] BMP280 initialized successfully");
            return;
        }
        delay(100);
    }

    Serial.println("[bmp280_pressure] Failed to initialize BMP280, retrying...");
}

float BMP280Pressure::getPressure() {
    if (bmp.readPressure()) {
        return bmp.seaLevelForAltitude(0); // Assuming sea level pressure is 1013.25 hPa
    } else {
        Serial.println("[bmp280_pressure] Failed to read pressure");
        return -1;
    }
}

float BMP280Pressure::getTemperature() {
    if (bmp.readTemperature()) {
        return bmp.temperature;
    } else {
        Serial.println("[bmp280_pressure] Failed to read temperature");
        return -1;
    }
}

float BMP280Pressure::getAltitude() {
    float pressure = getPressure();
    if (pressure != -1) {
        return bmp.readAltitude(1013.25); // Assuming sea level pressure is 1013.25 hPa
    } else {
        Serial.println("[bmp280_pressure] Failed to read altitude");
        return -1;
    }
}

