#include "eeprom_store.h"
#include <EEPROM.h>
#define EEPROM_SIZE 512
void eeprom_setup(){EEPROM.begin(EEPROM_SIZE);Serial.println("[eeprom] OK");}
void eeprom_write_int(int a,int v){EEPROM.put(a,v);EEPROM.commit();}
int eeprom_read_int(int a){int v;EEPROM.get(a,v);return v;}
void eeprom_write_float(int a,float v){EEPROM.put(a,v);EEPROM.commit();}
float eeprom_read_float(int a){float v;EEPROM.get(a,v);return v;}
void eeprom_write_string(int a,const char*s,int m){for(int i=0;i<m;i++)EEPROM.write(a+i,i<(int)strlen(s)?s[i]:0);EEPROM.commit();}
String eeprom_read_string(int a,int m){String s="";for(int i=0;i<m;i++){char c=EEPROM.read(a+i);if(!c)break;s+=c;}return s;}

