#include "sd_card.h"
#include <SD.h>
#include <SPI.h>
static bool _ok=false;
void sd_setup(){
  if(!SD.begin(5)){Serial.println("[sd] Init failed!");return;}
  _ok=true;Serial.printf("[sd] OK %lluMB\n",SD.cardSize()/1048576);
}
bool sd_log(const char*fn,const char*d){
  if(!_ok)return false;File f=SD.open(fn,FILE_APPEND);
  if(!f)return false;f.println(d);f.close();return true;
}
String sd_read(const char*fn){
  if(!_ok)return "";File f=SD.open(fn);if(!f)return"";
  String s=f.readString();f.close();return s;
}
bool sd_exists(const char*fn){return _ok&&SD.exists(fn);}
void sd_remove(const char*fn){if(_ok)SD.remove(fn);}

